import{_ as i,c as a,ag as o,o as l}from"./chunks/framework.mHuDn-wg.js";const u=JSON.parse('{"title":"命令行界面","description":"","frontmatter":{},"headers":[],"relativePath":"计算机/Windows/Windows.md","filePath":"计算机/Windows/Windows.md","lastUpdated":null}'),r={name:"计算机/Windows/Windows.md"};function t(n,e,s,d,c,h){return l(),a("div",null,e[0]||(e[0]=[o(`<h1 id="命令行界面" tabindex="-1">命令行界面 <a class="header-anchor" href="#命令行界面" aria-label="Permalink to &quot;命令行界面&quot;">​</a></h1><p><strong>Windows 有两个命令行工具</strong></p><h2 id="命令提示符-cmd-exe" tabindex="-1">命令提示符 cmd.exe <a class="header-anchor" href="#命令提示符-cmd-exe" aria-label="Permalink to &quot;命令提示符 cmd.exe&quot;">​</a></h2><ul><li>CMD 是Windows系统的一种命令行工具, 属于Windows系统的基本组件, 是一种直接操作系统的途径</li><li>功能: 文件和目录管理, 系统配置和维护, 网络管理, 故障排除, 自动化任务</li><li>原则上 cmd 命令不区分大小写</li></ul><h2 id="windows-powershell" tabindex="-1">Windows PowerShell <a class="header-anchor" href="#windows-powershell" aria-label="Permalink to &quot;Windows PowerShell&quot;">​</a></h2><ul><li>是一款功能强大的命令行界面（CLI）和脚本语言</li><li>兼容所有传统CMD命令, 扩展了cmd的功能(cmdle命令, 格式: &quot;动词-名词&quot;)</li><li>允许将几个命令组合起来放到文件里执行, 实现文件级的重用, 也就是说有脚本的性质, 比 .bat 脚本更加强大.</li><li>相关特定文件类型有<strong>脚本文件 (<code>.ps1</code>)</strong>、脚本数据文件 (<code>.psd1</code>) 和脚本模块文件 (<code>.psm1</code>)。</li><li>在PowerShell命令行输入脚本文件全名（xxx.ps1）即可运行</li><li>脚本文件.ps1和.bat的区别： <ul><li><code>.ps1</code> 是 PowerShell 脚本文件的扩展名，</li><li><code>.bat</code> 是 Windows 批处理脚本文件的扩展名，</li></ul></li><li>Windows对PowerShell脚本默认的执行策略是：不允许执行，即Restricted。</li><li>使用<code>get-executionpolicy</code> 可以在PowerShell命令行中查看执行策略，如果结果是Restricted，那表示禁止执行脚本。需要通过更改执行策略： <code>Set-ExecutionPolicy RemoteSigned</code> 或者 <code>set-executionpolicy -executionpolicy unrestricted</code></li><li>如果执行ps1文件，Powershell解释器会逐行解释并执行它的的语句</li><li><a href="https://www.pstips.net/powershell-online-tutorials/" target="_blank" rel="noreferrer">PowerShell 在线教程 – PowerShell 中文博客 (pstips.net)</a></li></ul><h1 id="常用windows命令" tabindex="-1">常用Windows命令 <a class="header-anchor" href="#常用windows命令" aria-label="Permalink to &quot;常用Windows命令&quot;">​</a></h1><h2 id="findstr" tabindex="-1">findstr <a class="header-anchor" href="#findstr" aria-label="Permalink to &quot;findstr&quot;">​</a></h2><ul><li>搜索文件中的文本，类似于linux的grep</li><li><a href="https://learn.microsoft.com/zh-cn/windows-server/administration/windows-commands/findstr" target="_blank" rel="noreferrer">findstr | Microsoft Learn</a></li></ul><h2 id="chcp" tabindex="-1">chcp <a class="header-anchor" href="#chcp" aria-label="Permalink to &quot;chcp&quot;">​</a></h2><ul><li>Windows操作系统默认编码格式是GBK（936）</li><li>查看cmd当前编码方式<code>chcp</code>, 会输出: 活动代码页：936</li><li><code>chcp 65001</code>会修改cmd编码方式为UTF-8</li></ul><h1 id="注册表-regedit" tabindex="-1">注册表 regedit <a class="header-anchor" href="#注册表-regedit" aria-label="Permalink to &quot;注册表 regedit&quot;">​</a></h1><ul><li>注册表编辑器（Regedit.exe），可以用来查看和维护注册表</li><li>Windows注册表(Registry)实质上是一个庞大的数据库，它存储着下面这些内容：用户计算机软、硬件的有关配置和状态信息，应用程序和资源管理器外壳的初始条件、首选项和卸载数据；计算机的整个系统的设置和各种许可，文件扩展名与应用程序的关联，硬件的描述、状态和属性；计算机性能记录和底层的系统状态信息，以及各类其他数据。</li><li>当前系统的注册表数据库在<code>C:\\Windows\\System32\\config</code></li><li>.ini文件：程序的配置文件。从Windows95系统开始，注册表开始全面替代ini文件，成为Windows系统中用于管理配置系统运行参数的核心数据库。这种集中管理的缺点是：不利于删除，软件的所有文件不存在于一个文件夹下，散落在系统的各个角落</li></ul><h1 id="程序安装路径-program-files" tabindex="-1">程序安装路径 Program Files <a class="header-anchor" href="#程序安装路径-program-files" aria-label="Permalink to &quot;程序安装路径 Program Files&quot;">​</a></h1><ul><li>有的程序会调用命令行，空格在命令中具有特殊意义，需要转义，为了避免出错一些程序要求安装路径中不允许有空格。</li><li>很多软件的exe喜欢放在本该存放数据的Appdata文件夹下，以规避更改Program Files文件夹内容需要的权限限制，实现静默升级</li><li>位置：System32主要是系统程序，Program Files是第三方程序 ![[Pasted image 20240628103042.png|500]] ![[Pasted image 20240628102943.png|250]]</li><li>对于64位的系统： ![[Pasted image 20240628103804.png|250]]</li></ul><h1 id="wsl" tabindex="-1">WSL <a class="header-anchor" href="#wsl" aria-label="Permalink to &quot;WSL&quot;">​</a></h1><p>WSL 与 Windows 之间有很好的互操作性，可以进行文件共享和相互访问。</p><ol><li>文件访问：你可以在 Linux 发行版的终端中访问 Windows 文件系统，路径为 <code>/mnt/&lt;盘符&gt;</code>。例如，<code>/mnt/c/</code> 是访问 C 盘的路径。</li><li>Windows 访问 Linux 文件：打开 “资源管理器”，在地址栏输入 <code>\\\\wsl$</code>，即可访问 Linux 文件系统。</li><li>与 Windows 应用程序集成：WSL 支持在 Linux 中运行一些基于文本的 Windows 应用程序，例如编辑器和浏览器。</li><li><a href="https://learn.microsoft.com/zh-cn/windows/wsl/install#upgrade-version-from-wsl-1-to-wsl-2" target="_blank" rel="noreferrer">安装 WSL | Microsoft Learn</a></li><li><a href="https://zhuanlan.zhihu.com/p/584398122" target="_blank" rel="noreferrer">windows10操作系统下使用WSL2安装Ubuntu22.04.5系统 - 知乎 (zhihu.com)</a></li><li><a href="https://zhuanlan.zhihu.com/p/605603032" target="_blank" rel="noreferrer">WSL中调用Windows下软件 - 知乎 (zhihu.com)</a><a href="https://learn.microsoft.com/zh-cn/windows/wsl/setup/environment" target="_blank" rel="noreferrer">设置 WSL 开发环境 | Microsoft Learn</a> 查看wsl版本： wsl -l -v 或 wsl --list --verbose</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> NAME      STATE           VERSION</span></span>
<span class="line"><span>* Debian    Stopped         1</span></span></code></pre></div><p>查看Linux发行版的版本：</p><ul><li><strong>Ubuntu/Debian</strong>：cat /etc/os-release</li><li><strong>CentOS/Red Hat</strong>：cat /etc/centos-release 或 cat /etc/os-release</li></ul><p><a href="https://learn.microsoft.com/zh-cn/windows/wsl/install-manual" target="_blank" rel="noreferrer">旧版 WSL 的手动安装步骤 | Microsoft Learn</a> 请确保你的Windows 10版本至少是2020年4月更新（2004版），因为WSL 2是在这个版本中引入的。如果你的系统不支持WSL 2，你需要更新你的Windows版本或者手动安装WSL 2的内核组件。 将 WSL 2 设置为默认版本： wsl --set-default-version 2 切换 WSL 版本： wsl --set-version &lt;发行版名称&gt; 2</p><p>默认情况下，安装的 Linux 分发版为 Ubuntu。 可以使用 <code>-d</code> 标志进行更改。</p><ul><li>若要更改安装的发行版，请输入：<code>wsl --install -d &lt;Distribution Name&gt;</code>。 将 <code>&lt;Distribution Name&gt;</code> 替换为要安装的发行版的名称。</li><li>若要查看可通过在线商店下载的可用 Linux 发行版列表，请输入：<code>wsl --list --online</code> 或 <code>wsl -l -o</code>。</li><li>若要在初始安装后安装其他 Linux 发行版，还可使用命令：<code>wsl --install -d &lt;Distribution Name&gt;</code>。 ![[Pasted image 20240901151011.png]] <a href="https://www.cnblogs.com/wanderoff-night/p/17988720" target="_blank" rel="noreferrer">在 Windows 中配置 WSL2 与 Debian 的全流程 - 总之先找时光机！ - 博客园 (cnblogs.com)</a><a href="http://bbs.keinsci.com/thread-25516-1-1.html" target="_blank" rel="noreferrer">GROMACS-GPU版在WSL2-Ubuntu中的安装方法 - 分子模拟 (Molecular Modeling) - 计算化学公社 (keinsci.com)</a></li></ul><p>WSLg 是Windows Subsystem for Linux GUI的缩写，意图在WSL中支持直接运行Linux GUI程序，界面和Windows桌面环境无缝集成。</p><h1 id="windows启动管理器" tabindex="-1">Windows启动管理器 <a class="header-anchor" href="#windows启动管理器" aria-label="Permalink to &quot;Windows启动管理器&quot;">​</a></h1><p>Windows Boot Manager（Windows启动管理器）是引导操作系统启动的一个工具，当我们的电脑安装了多个操作系统时，我们就可以调出启动管理器，在电脑启动时就会在显示操作系统的选择界面，让我们选择自己想要的系统来启动。 ![[Pasted image 20240709153423.png|500]]</p><h1 id="开机自启动" tabindex="-1">开机自启动 <a class="header-anchor" href="#开机自启动" aria-label="Permalink to &quot;开机自启动&quot;">​</a></h1><p>程序的开机自启动管理：任务管理器&gt;启动</p><h1 id="安全模式" tabindex="-1">安全模式 <a class="header-anchor" href="#安全模式" aria-label="Permalink to &quot;安全模式&quot;">​</a></h1><p>安全模式的工作原理是在不加载第三方设备驱动程序的情况下启动电脑，使电脑运行在系统最小模式，这样用户就可以方便地检测与修复计算机系统的错误。 包括： 启用安全模式。 通过网络启用安全模式。 使用命令提示符启用安全模式。 ![[Pasted image 20240709153546.png|400]]</p><h1 id="pe" tabindex="-1">PE <a class="header-anchor" href="#pe" aria-label="Permalink to &quot;PE&quot;">​</a></h1><p>Windows PE (WinPE，Windows preinstallation environment)，是一个小型操作系统，用于安装、部署和修复 Windows 桌面版、Windows Server 和其他 Windows 操作系统。衍生了很多的个性化工具，包括：磁盘管理、备份还原、UFEI引导修复、硬件检测、账户密码破解、数据恢复…… 可从 U 盘、CD/DVD/ISO 或虚拟硬盘驱动器启动 WinPE。 WinPE可以被第三方修改，有各种版本的PE：<a href="https://www.wepe.com.cn/" target="_blank" rel="noreferrer">微PE</a>、<a href="https://home.edgeless.top/#" target="_blank" rel="noreferrer">Edgeless</a>、优启通、FirPE、<a href="https://www.hirensbootcd.org/" target="_blank" rel="noreferrer">Hiren&#39;s BootCD PE</a> ![[Pasted image 20240709110148.png|300]] PE运行在内存中（会将部分内存转化为临时磁盘） <a href="https://learn.microsoft.com/zh-cn/windows-hardware/manufacture/desktop/winpe-intro?view=windows-11" target="_blank" rel="noreferrer">Windows PE (WinPE) | Microsoft Learn</a></p><h1 id="虚拟内存-分页文件" tabindex="-1">虚拟内存/分页文件 <a class="header-anchor" href="#虚拟内存-分页文件" aria-label="Permalink to &quot;虚拟内存/分页文件&quot;">​</a></h1><h1 id="动态链接库-dll" tabindex="-1">动态链接库 dll <a class="header-anchor" href="#动态链接库-dll" aria-label="Permalink to &quot;动态链接库 dll&quot;">​</a></h1><h1 id="字体" tabindex="-1">字体 <a class="header-anchor" href="#字体" aria-label="Permalink to &quot;字体&quot;">​</a></h1><p>在 C:\\Windows\\Fonts 目录下存放着Windows字体库</p><h1 id="visual-studio" tabindex="-1">Visual Studio <a class="header-anchor" href="#visual-studio" aria-label="Permalink to &quot;Visual Studio&quot;">​</a></h1><p>Visual Studio是微软公司推出的一款集成开发环境（IDE），广泛应用于计算机程序、网站、Web应用、Web服务和移动应用的软件开发。主要用于适用于Windows平台</p><p>Windows Kits是一个专为Windows应用程序开发设计的工具包。Windows Kits文件夹通常位于Visual Studio的安装目录下，包含了编译器、调试器、性能分析器、资源编辑器等工具，以及Windows SDK和驱动程序开发工具，确保开发者能够创建高效、可靠且符合标准的Windows应用程序。</p>`,40)]))}const p=i(r,[["render",t]]);export{u as __pageData,p as default};
